// poLineItemOptionLabel formats a product option label as
// "<SKU — ><name> · <kind>" where kind is "stock" or "service".
// Kept exported even though the migrated editor uses balancizItemPicker
// instead of a native <select>: PDF templates and other consumers may
// reuse the helper.
func poLineItemOptionLabel(p models.ProductService) string {
	kind := "service"
	if p.IsStockItem {
		kind = "stock"
	}
	name := p.Name
	if p.SKU != "" {
		name = p.SKU + " — " + p.Name
	}
	return name + " · " + kind
}

// poLineQtyDisplay renders Qty + UOM snapshot for a single PO line on
// the read-only path. PO is buy-side, so the snapshot UOM defaults to
// the product's PurchaseUOM at create time.
func poLineQtyDisplay(line models.PurchaseOrderLine) string {
	isStock := false
	stockUOM := ""
	if line.ProductService != nil {
		isStock = line.ProductService.IsStockItem
		stockUOM = line.ProductService.StockUOM
	}
	return QtyWithUOM(line.Qty, isStock, line.LineUOM, line.LineUOMFactor, stockUOM)
}

